GOLD  <- "#C9A84C"
BLACK <- "#1A1A1A"
WHITE <- "#FFFFFF"

# ── DATA LOADER ────────────────────────────────────────────────────────────────
APP_DIR <- getwd()

load_csv <- function(fname) {
  path <- file.path(APP_DIR, fname)
  if (!file.exists(path)) return(NULL)
  tryCatch(read_csv(path, show_col_types = FALSE), error = function(e) NULL)
}

# ── SHARED GGPLOT THEME ────────────────────────────────────────────────────────
theme_crc <- function(base_size = 12) {
  theme_minimal(base_size = base_size) +
    theme(
      plot.background    = element_rect(fill = WHITE, colour = NA),
      panel.background   = element_rect(fill = WHITE, colour = NA),
      panel.grid.major.x = element_blank(),
      panel.grid.major.y = element_line(colour = "#EBEBEB", linewidth = 0.5),
      panel.grid.minor   = element_blank(),
      axis.text          = element_text(colour = DGRAY, size = 10),
      axis.title         = element_text(colour = DGRAY, size = 11),
      plot.title         = element_text(colour = NAVY,  size = 13,
                                        face = "bold", hjust = 0),
      plot.subtitle      = element_text(colour = DGRAY, size = 10, hjust = 0),
      plot.caption       = element_text(colour = "#AAAAAA", size = 8, hjust = 0),
      legend.background  = element_rect(fill = WHITE, colour = NA),
      legend.key         = element_rect(fill = WHITE, colour = NA),
      strip.text         = element_text(colour = NAVY, face = "bold")
    )
}

