# ── SERVER ─────────────────────────────────────────────────────────────────────
server <- function(input, output, session) {

  # ── LOAD DATA ───────────────────────────────────────────────────────────────
  kpi        <- reactive({ load_csv("crc_kpi.csv") })
  raw        <- reactive({ load_csv("crc_trials_raw.csv") })
  terms      <- reactive({ load_csv("crc_top_terms.csv") })
  clf_res    <- reactive({ load_csv("crc_classifier_results.csv") })
  roc_data   <- reactive({ load_csv("crc_roc_curves.csv") })
  pr_data    <- reactive({ load_csv("crc_pr_curves.csv") })
  shap_data  <- reactive({ load_csv("crc_shap_values.csv") })
  calib_data <- reactive({ load_csv("crc_calibration.csv") })
  online_data<- reactive({ load_csv("crc_online_learning.csv") })
  embed_data <- reactive({ load_csv("crc_embedding_comparison.csv") })
  lsa_data   <- reactive({ load_csv("crc_lsa_variance.csv") })

  # ── HELPER: get KPI value ───────────────────────────────────────────────────
  kpi_val <- function(metric) {
    df <- kpi()
    if (is.null(df)) return("—")
    v <- df$Value[df$Metric == metric]
    if (length(v) == 0) return("—")
    as.character(v[1])
  }

  # ── VALUE BOXES ─────────────────────────────────────────────────────────────
  output$vb_trials <- renderValueBox({
    valueBox(kpi_val("Total CRC trials"), "CRC Trials Analysed",
             icon = icon("flask"), color = "blue")
  })
  output$vb_failure <- renderValueBox({
    v <- kpi_val("Overall failure rate")
    pct <- tryCatch(paste0(round(as.numeric(v)*100, 1), "%"), error=function(e) v)
    valueBox(pct, "Overall Failure Rate",
             icon = icon("triangle-exclamation"), color = "red")
  })
  output$vb_best_auc <- renderValueBox({
    valueBox(kpi_val("Best test AUC"), "Best Test AUC",
             icon = icon("chart-line"), color = "green")
  })
  output$vb_features <- renderValueBox({
    valueBox(kpi_val("TF-IDF features"), "TF-IDF Features",
             icon = icon("font"), color = "yellow")
  })

  # ── KPI TABLE ───────────────────────────────────────────────────────────────
  output$kpi_table <- renderTable({
    df <- kpi()
    if (is.null(df)) return(data.frame(Metric="No data", Value="—"))
    df
  }, striped = TRUE, hover = TRUE, bordered = TRUE)

  # ── DATA EXPLORER ───────────────────────────────────────────────────────────
  observe({
    df <- raw()
    if (is.null(df)) return()
    phases   <- c("All", sort(unique(df$phase[!is.na(df$phase) & df$phase != ""])))
    sponsors <- c("All", sort(unique(df$sponsor_class[!is.na(df$sponsor_class) & df$sponsor_class != ""])))
    updateSelectInput(session, "exp_phase",   choices = phases)
    updateSelectInput(session, "exp_sponsor", choices = sponsors)
  })

  output$raw_table <- DT::renderDataTable({
    df <- raw()
    if (is.null(df)) return(data.frame(Message = "No data loaded"))
    if (input$exp_status != "All") df <- df[df$status == input$exp_status, ]
    if (!is.null(input$exp_phase) && input$exp_phase != "All")
      df <- df[!is.na(df$phase) & df$phase == input$exp_phase, ]
    if (!is.null(input$exp_sponsor) && input$exp_sponsor != "All")
      df <- df[!is.na(df$sponsor_class) & df$sponsor_class == input$exp_sponsor, ]
    cols_show <- intersect(c("nct_id","title","status","phase",
                              "sponsor_class","enrollment","start_year"), names(df))
    DT::datatable(df[, cols_show], options = list(pageLength = 15, scrollX = TRUE))
  })

  # ── TF-IDF PLOT ─────────────────────────────────────────────────────────────
  output$tfidf_plot <- renderPlot({
    df <- terms()
    if (is.null(df)) return(NULL)
    n  <- input$n_terms
    grp <- input$term_group
    if (grp != "Both") df <- df[df$group == grp, ]
    df <- df %>% group_by(group) %>% slice_max(mean_tfidf, n = n) %>% ungroup()
    df$fill_col <- ifelse(df$group == "Failed", RED, GREEN)
    ggplot(df, aes(x = reorder(term, mean_tfidf), y = mean_tfidf, fill = group)) +
      geom_col(alpha = 0.85, show.legend = TRUE) +
      scale_fill_manual(values = c("Failed" = RED, "Completed" = GREEN),
                        name = "Trial outcome") +
      coord_flip() +
      facet_wrap(~group, scales = "free_y") +
      labs(title = "Top TF-IDF Terms by Trial Outcome",
           subtitle = paste("Top", n, "terms by mean TF-IDF score"),
           x = NULL, y = "Mean TF-IDF Score",
           caption = "Ref: Pedregosa et al. (2011) JMLR 12:2825 — scikit-learn TF-IDF") +
      theme_crc()
  })

  output$tfidf_table <- DT::renderDataTable({
    df <- terms()
    if (is.null(df)) return(data.frame(Message = "No data"))
    DT::datatable(df, options = list(pageLength = 20, scrollX = TRUE))
  })

  # ── ROC PLOT ────────────────────────────────────────────────────────────────
  clf_pal <- c("Logistic Regression" = NAVY,
               "Random Forest"       = GREEN,
               "Gradient Boosting"   = BLUE,
               "SVM (linear)"        = AMBER)

  output$roc_plot <- renderPlot({
    df <- roc_data()
    cr <- clf_res()
    if (is.null(df)) return(NULL)
    auc_labs <- NULL
    if (!is.null(cr)) {
      auc_labs <- setNames(
        paste0(cr$Classifier, " (AUC=", cr$`Test AUC`, ")"),
        cr$Classifier)
    }
    if (!is.null(auc_labs)) {
      df$clf_lab <- auc_labs[df$Classifier]
    } else {
      df$clf_lab <- df$Classifier
    }
    ggplot(df, aes(x = FPR, y = TPR, colour = Classifier)) +
      geom_line(linewidth = 1.2) +
      geom_abline(slope = 1, intercept = 0, linetype = "dashed",
                  colour = GREY, linewidth = 0.8) +
      scale_colour_manual(values = clf_pal) +
      labs(title = "ROC Curves",
           subtitle = "20% stratified hold-out test set",
           x = "False Positive Rate", y = "True Positive Rate",
           colour = "Classifier",
           caption = "Ref: Saito & Rehmsmeier (2015) PLOS ONE — PR curves for imbalanced data") +
      theme_crc() + theme(panel.grid.major.x = element_line(colour="#EBEBEB"))
  })

  # ── PR PLOT ─────────────────────────────────────────────────────────────────
  output$pr_plot <- renderPlot({
    df <- pr_data()
    cr <- clf_res()
    if (is.null(df)) return(NULL)
    base_rate <- tryCatch(as.numeric(kpi_val("Overall failure rate")), error=function(e) NULL)
    p <- ggplot(df, aes(x = Recall, y = Precision, colour = Classifier)) +
      geom_line(linewidth = 1.2) +
      scale_colour_manual(values = clf_pal) +
      labs(title = "Precision-Recall Curves",
           subtitle = "Higher area = better performance on imbalanced data",
           x = "Recall", y = "Precision", colour = "Classifier") +
      theme_crc() + theme(panel.grid.major.x = element_line(colour="#EBEBEB"))
    if (!is.null(base_rate))
      p <- p + geom_hline(yintercept = base_rate, linetype = "dashed",
                          colour = GREY, linewidth = 0.8)
    p
  })

  # ── PERF TABLE ──────────────────────────────────────────────────────────────
  output$perf_table <- DT::renderDataTable({
    df <- clf_res()
    if (is.null(df)) return(data.frame(Message = "No data"))
    DT::datatable(df, options = list(pageLength = 10)) %>%
      DT::formatStyle("Test AUC",
        backgroundColor = DT::styleInterval(c(0.65, 0.75),
                            c(AMB_L, GRN_L, "#D4EDDA")))
  })

  # ── SHAP PLOT ───────────────────────────────────────────────────────────────
  output$shap_plot <- renderPlot({
    df <- shap_data()
    if (is.null(df)) return(NULL)
    n   <- input$n_shap
    dir <- input$shap_dir
    if (dir != "Both") df <- df[df$direction == dir, ]
    df <- df %>% arrange(desc(mean_shap)) %>% slice_head(n = n)
    df$fill_col <- ifelse(df$direction == "Failure", RED, GREEN)
    ggplot(df, aes(x = reorder(feature, mean_shap), y = mean_shap,
                   fill = direction)) +
      geom_col(alpha = 0.85) +
      scale_fill_manual(values = c("Failure" = RED, "Success" = GREEN),
                        name = "Prediction direction") +
      coord_flip() +
      geom_text(aes(label = sprintf("%.4f", mean_shap)),
                hjust = -0.1, size = 3.2, colour = DGRAY) +
      labs(title = "SHAP Feature Importance — Logistic Regression",
           subtitle = "Mean absolute SHAP value across 500 test observations",
           x = NULL, y = "Mean |SHAP Value|",
           caption = "Ref: Lundberg & Lee (2017) NeurIPS — SHAP unified framework") +
      theme_crc() + theme(panel.grid.major.x = element_line(colour="#EBEBEB"))
  })

  output$shap_table <- DT::renderDataTable({
    df <- shap_data()
    if (is.null(df)) return(data.frame(Message = "No data"))
    DT::datatable(df, options = list(pageLength = 20, scrollX = TRUE)) %>%
      DT::formatStyle("direction",
        backgroundColor = DT::styleEqual(c("Failure","Success"), c(RED_L, GRN_L)))
  })

  # ── CALIBRATION PLOT ────────────────────────────────────────────────────────
  output$calib_plot <- renderPlot({
    df <- calib_data()
    if (is.null(df)) return(NULL)
    ggplot(df, aes(x = mean_pred_prob, y = fraction_pos, colour = Classifier)) +
      geom_line(linewidth = 1.2) +
      geom_point(size = 3) +
      geom_abline(slope = 1, intercept = 0, linetype = "dashed",
                  colour = GREY, linewidth = 1) +
      scale_colour_manual(values = clf_pal) +
      labs(title = "Reliability Diagrams",
           subtitle = "Diagonal = perfect calibration",
           x = "Mean Predicted Probability", y = "Fraction of Positives",
           caption = "Ref: Brier (1950) Mon Weather Rev — proper scoring rules") +
      theme_crc() + theme(panel.grid.major.x = element_line(colour="#EBEBEB"))
  })

  output$brier_plot <- renderPlot({
    df <- calib_data()
    if (is.null(df)) return(NULL)
    brier_df <- df %>%
      group_by(Classifier) %>%
      summarise(brier_score = first(brier_score), .groups="drop") %>%
      arrange(brier_score)
    brier_df$fill_col <- ifelse(brier_df$brier_score < 0.15, GREEN,
                          ifelse(brier_df$brier_score < 0.20, AMBER, RED))
    ggplot(brier_df, aes(x = reorder(Classifier, brier_score),
                          y = brier_score, fill = fill_col)) +
      geom_col(alpha = 0.85, show.legend = FALSE) +
      scale_fill_identity() +
      geom_text(aes(label = sprintf("%.3f", brier_score)),
                vjust = -0.4, size = 4, colour = BLACK) +
      coord_cartesian(ylim = c(0, max(brier_df$brier_score)*1.25)) +
      labs(title = "Brier Score (lower = better)",
           subtitle = "Measures calibration quality",
           x = NULL, y = "Brier Score") +
      theme_crc()
  })

  # ── ONLINE LEARNING PLOT ─────────────────────────────────────────────────────
  output$online_plot <- renderPlot({
    df <- online_data()
    if (is.null(df)) return(NULL)
    sm <- input$online_smooth
    if (sm > 1 && nrow(df) > sm) {
      df$window_auc <- stats::filter(df$window_auc,
                                      rep(1/sm, sm), sides=2) %>%
                       as.numeric()
      df$window_ap  <- stats::filter(df$window_ap,
                                      rep(1/sm, sm), sides=2) %>%
                       as.numeric()
      df <- df[!is.na(df$window_auc), ]
    }
    base_rate <- tryCatch(as.numeric(kpi_val("Overall failure rate")), error=function(e) NULL)
    p1 <- ggplot(df, aes(x = n_train)) +
      geom_ribbon(aes(ymin = pmin(window_auc, window_ap),
                       ymax = pmax(window_auc, window_ap)),
                  fill = NAVY, alpha = 0.08) +
      geom_line(aes(y = window_auc, colour = "AUC"),  linewidth = 1.8) +
      geom_line(aes(y = window_ap,  colour = "AP"),   linewidth = 1.4, linetype="dashed") +
      scale_colour_manual(values = c("AUC" = NAVY, "AP" = BLUE), name = NULL) +
      labs(title = "A — Window AUC and AP vs Training Size",
           x = "Training Set Size (N trials)", y = "Performance",
           caption = "Ref: Gama et al. (2014) ACM Comput Surv — prequential evaluation") +
      theme_crc()
    if (!is.null(base_rate))
      p1 <- p1 + geom_hline(yintercept = base_rate, linetype="dotted",
                              colour=RED, linewidth=0.8)
    gridExtra::grid.arrange(p1, ncol=1)
  })

  # ── EMBEDDINGS PLOT ─────────────────────────────────────────────────────────
  output$embed_plot <- renderPlot({
    df <- embed_data()
    if (is.null(df)) return(NULL)
    df$fill_col <- c(NAVY, BLUE, GREEN)[seq_len(nrow(df))]
    ggplot(df, aes(x = reorder(Method, `Test AUC`), y = `Test AUC`, fill = fill_col)) +
      geom_col(alpha = 0.85, show.legend = FALSE, width = 0.5) +
      scale_fill_identity() +
      geom_text(aes(label = sprintf("%.3f", `Test AUC`)),
                vjust = -0.4, size = 4.5, colour = BLACK, fontface = "bold") +
      coord_cartesian(ylim = c(0, 1)) +
      labs(title = "AUC by Representation Method",
           subtitle = "TF-IDF vs LSA semantic embeddings",
           x = NULL, y = "Test AUC",
           caption = "Deerwester et al. (1990) JASIST — LSA") +
      theme_crc()
  })

  output$lsa_plot <- renderPlot({
    df <- lsa_data()
    if (is.null(df)) return(NULL)
    df_plot <- df[df$component <= 50, ]
    ggplot(df_plot, aes(x = component)) +
      geom_col(aes(y = explained_variance * 100),
               fill = NAVY, alpha = 0.6, width = 0.8) +
      geom_line(aes(y = cumulative_variance * 100),
                colour = RED, linewidth = 1.5) +
      geom_point(aes(y = cumulative_variance * 100),
                 colour = RED, size = 1.5) +
      scale_y_continuous(
        name = "Variance Explained (%)",
        sec.axis = dup_axis(name = "Cumulative (%)")
      ) +
      labs(title = "LSA Explained Variance (first 50 components)",
           subtitle = "Bars = per-component; Red line = cumulative",
           x = "Component", caption = "TruncatedSVD (scikit-learn)") +
      theme_crc()
  })

}

# ── LAUNCH ─────────────────────────────────────────────────────────────────────
shinyApp(ui = ui, server = server)
